class Solution(object):
    def checkArray(self, nums, k):
        n = len(nums)
        delta = [0] * (n + 1)
        current = 0
        for i in range(n):
            current += delta[i]
            remaining = nums[i] - current
            if remaining < 0:
                return False
            if remaining > 0:
                if i + k > n:
                    return False
                current += remaining
                delta[i + k] -= remaining
        return True
